import 'package:bookly/Features/Home/Data/Repos/home_repo.dart';import 'package:flutter/material.dart';import 'package:flutter_bloc/flutter_bloc.dart';import '../../Data/model/book_model.dart';part 'featured_state.dart';class FeaturedCubit extends Cubit<FeaturedState> {  FeaturedCubit(this.homeRepo) : super(FeaturedInitial());  static FeaturedCubit get(context) => BlocProvider.of(context);  final HomeRepo homeRepo;  Future<void> fetchNewsBooksBooks() async {    emit(FeaturedLoading());    var result = await homeRepo.fetchFeaturedBooks();    result.fold((failure) {      emit(FeaturedFailure(error: failure.errMessage));    },        (books) {      emit(FeaturedSuccess(books: books));    });  }}